let data = msg.payload;
if (typeof msg.payload === 'string') {
    try {
        data = JSON.parse(msg.payload);
    } catch(e) {
        node.warn('Failed to parse: ' + e.message);
        return null;
    }
}

let now = new Date();
msg.parsed = {
    device_id: data.device_id || 2,
    class_code: 'Q1.01.03',
    consumption: parseFloat(data.power || data.consumption || 0),
    temperature: data.temperature ? parseFloat(data.temperature) : null,
    humidity: data.humidity ? parseFloat(data.humidity) : null,
    consumption_date: now.toISOString().split('T')[0],
    hour_start: now.getHours().toString().padStart(2,'0') + ':00:00',
    hour_end: now.getHours().toString().padStart(2,'0') + ':59:59',
    raw_payload: data
};

return msg;

let p = msg.parsed;

if (!p.device_id) {
    node.warn('Missing device_id');
    return null;
}

if (p.consumption < 0 || p.consumption > 100) {
    node.warn('Consumption out of range: ' + p.consumption);
}

if (p.temperature && (p.temperature < -50 || p.temperature > 60)) {
    node.warn('Temperature invalid: ' + p.temperature);
}

if (p.humidity && (p.humidity < 0 || p.humidity > 100)) {
    node.warn('Humidity invalid: ' + p.humidity);
}

node.status({fill:'green', shape:'dot', text:'Valid'});
return msg;

let text = msg.payload;
try {
    let data = JSON.parse(text);
    if (data.success || data.id) {
        node.status({fill:'green', shape:'dot', text:'Saved @ ' + new Date().toLocaleTimeString()});
        return msg;
    } else {
        node.warn('API Error: ' + (data.message || 'Unknown'));
        node.status({fill:'red', shape:'ring', text:'Error'});
        return null;
    }
} catch(e) {
    node.warn('Parse error: ' + e.message);
    node.status({fill:'red', shape:'ring', text:'Error'});
    return null;
}
